def smallestNumber(self, pattern: str) -> str:
    n = len(pattern)
    num = [0] * (n + 1)
    for i in range(n):
        if pattern[i] == 'I':
            num[i] = num[i + 1] + 1
        elif pattern[i] == 'D':
            num[i] = num[i + 1] - 1
    return ''.join(str(num[i]) for i in range(n))

